
(function RetroV(){var create_callbacks=[];function user_render(dom_container,v){var vlist=[v];var old_vlist=[];var new_vlist=make_children(vlist);if(dom_container.rv_old_vlist){old_vlist=dom_container.rv_old_vlist;}
else
{dom_container.replaceChildren();}
dom_container.rv_old_vlist=new_vlist;render_children(dom_container,old_vlist,new_vlist);create_callbacks.forEach(function(cc){cc.fn(cc.el);});create_callbacks=[];}
function render(dom_container,old_v,new_v,dom_index){var child=dom_container.childNodes[dom_index];if(typeof new_v==='undefined'){dom_container.removeChild(child);return;}
if(new_v.t===false){if(typeof old_v==='undefined'){dom_container.append(placeholder('false'));}
return;}
if(typeof old_v==='undefined'){dom_container.appendChild(create(new_v));return;}
if(old_v.t!==new_v.t){child.replaceWith(create(new_v));return;}
if(!new_v.t||new_v.t==='!'){return;}
update(child,old_v,new_v);}
function create(v){if(v.t==='"'){return document.createTextNode(v.text);}
if(v.t===null){return placeholder('null');}
if(v.t===false){return placeholder('false');}
if(v.t==='!'){return placeholder('undefined');}
if(v.t==='<'){return create_html(v.html);}
try{var el=document.createElement(v.t);}catch(e){if(e instanceof DOMException){console.error("RetroV: Bad element name: ",v.t);}
throw e;}
Object.keys(v.p).forEach(function(k){if(k==='style'){set_or_update_style(el,{},v);return;}
if(k==='for'){el['htmlFor']=v.p['for'];return;}
if(k==='rvid'){RV.id[v.p[k]]=el;}
if(k==='oncreate'&&typeof v.p[k]==='function'){create_callbacks.push({el:el,fn:v.p[k]});return;}
el[k]=v.p[k];});v.c.forEach(function(child){el.append(create(child));});return el;}
function create_html(html){var d=document.createElement('div');d.innerHTML=html;return d.childNodes[0];}
function placeholder(t){return document.createComment('RV:'+t+'-placeholder');}
function set_or_update_style(dom_elem,old_v,new_v){var old_style=(old_v.p&&old_v.p.style?old_v.p.style:{});Object.keys(new_v.p.style).forEach(function(sk){if(new_v.p.style[sk]!=old_style[sk]){dom_elem.style[sk]=new_v.p.style[sk];}});}
function update(dom_elem,old_v,new_v){if(new_v.t==='"'){dom_elem.data=new_v.text;return;}
if(new_v.t==='<'&&new_v.html!==old_v.html){dom_elem.replaceWith(create_html(new_v.html));return;}
Object.keys(new_v.p).forEach(function(k){if(k==='style'){set_or_update_style(dom_elem,old_v,new_v);return;}
if(k==='value'||k==='checked'){dom_elem[k]=new_v.p[k];return;}
if(new_v.p[k]!==old_v.p[k]){dom_elem[k]=new_v.p[k];}});render_children(dom_elem,old_v.c,new_v.c);}
function render_children(dom_elem,old_c,new_c){if(old_c.length>new_c.length){for(var i=old_c.length-1;i>=0;i--){render(dom_elem,old_c[i],new_c[i],i);}}
else{for(var i=0;i<new_c.length;i++){render(dom_elem,old_c[i],new_c[i],i);}}}
function make_obj(v){if(typeof v==='string'||typeof v==='number'){return{t:'"',text:v};}
if(Array.isArray(v)&&typeof v[0]==='string'&&v[0][0]==='<'){return{t:'<',html:v};}
if(v===null){return{t:null};}
if(v===false){return{t:false};}
if(v===undefined){return{t:'!'};}
if(Array.isArray(v)&&typeof v[0]==='string'){var child_start=1;var props={};if(v[1]&&typeof v[1]==='object'&&!Array.isArray(v[1])){props=v[1];if(typeof props['class']!=='undefined'){props['className']=props['class'];delete props['class'];}
if(typeof props['for']!=='undefined'){props['htmlFor']=props['for'];delete props['for'];}
child_start=2;}
var tag=v[0];var myclasses=[];var m=tag.split('.');var mytag=m.shift();if(mytag.length===0){mytag='div';}
m.forEach(function(v){myclasses.push(v);});if(myclasses.length>0){props.className=props.className?props.className+' '+myclasses.join(' '):myclasses.join(' ');}
var children=make_children(v.slice(child_start));return{t:mytag,p:props,c:children};}
console.error("RetroV: make_obj() cannot handle this:",v);}
function make_children(vlist){var objs=[];vlist.forEach(function(v){if(!Array.isArray(v)||typeof v[0]==='string'){objs.push(make_obj(v));}
else{make_children(v).forEach(function(flat_v){objs.push(flat_v);});}});return objs;}
window.RV={render:user_render,id:[]};})();